wwv_flow_imp_page.create_page_da_action(
 p_id=>wwv_flow_imp.id(150133755889438102930)
,p_event_id=>wwv_flow_imp.id(150133755775955102929)
,p_event_result=>'TRUE'
,p_action_sequence=>10
,p_execute_on_page_init=>'N'
,p_action=>'NATIVE_JAVASCRIPT_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'// Get the output content',
'var content = $v(''P3_OUTPUT'');',
'',
'// Get the format from the hidden item',
'var format  = $v(''P3_OUTPUT_FORMAT'');',
'',
'// Map format to file extension and MIME type',
'var fileName, mimeType;',
'',
'if (format === ''MARKDOWN'') {',
'    fileName = ''schema-docs.md'';',
'    mimeType = ''text/markdown'';',
'} else if (format === ''JSON'') {',
'    fileName = ''schema-docs.json'';',
'    mimeType = ''application/json'';',
'} else {',
'    fileName = ''schema-docs.txt'';',
'    mimeType = ''text/plain'';',
'}',
'',
'// Create a blob and trigger the download',
'var blob = new Blob([content], { type: mimeType });',
'var url  = URL.createObjectURL(blob);',
'',
'var a    = document.createElement(''a'');',
'a.href  = url;',
'a.download = fileName;',
'document.body.appendChild(a);',
'a.click();',
'',
'// Cleanup',
'document.body.removeChild(a);',
'URL.revokeObjectURL(url);'))
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(150133754779083102919)
,p_process_sequence=>10
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'generate output'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'  IF :P2_OUTPUT_FORMAT = ''MARKDOWN'' THEN',
'    :P3_OUTPUT := apex_schema_docs_pkg.generate_markdown(:P2_SELECTED_TABLES);',
'  ELSIF :P2_OUTPUT_FORMAT = ''JSON'' THEN',
'    :P3_OUTPUT := apex_schema_docs_pkg.generate_json(:P2_SELECTED_TABLES);',
'  ELSE',
'    :P3_OUTPUT := apex_schema_docs_pkg.generate_plain_text(:P2_SELECTED_TABLES);',
'  END IF;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_internal_uid=>150133754779083102919
);
end;
